def validate_lambda_response(response):
    try:
        action_group_output = response['completion'].get('actionGroupsResponse', [{}])[0]
        output = action_group_output.get('apiResponse', {}).get('body', {})

        # Bedrock expects JSON-parseable string in body
        if isinstance(output, str):
            parsed = json.loads(output)
        else:
            parsed = output

        # Validate required fields
        if 'completion' not in parsed or 'message' not in parsed['completion']:
            return {'valid': False, 'error': 'Missing required completion.message field'}

        return {'valid': True}
    except Exception as e:
        return {'valid': False, 'error': str(e)}

import boto3
from sentence_transformers import SentenceTransformer, util

model = SentenceTransformer('all-MiniLM-L6-v2')

bedrock = boto3.client('bedrock-agent-runtime')

def check_kb_coverage(response, expected_query):
    try:
        trace = response['trace']
        kb_blocks = [step for step in trace if step['type'] == 'knowledgeBaseRetrieval']

        if not kb_blocks:
            return {'coverage': 0.0, 'missing': True}

        # Extract retrieved content
        retrieved_texts = []
        for block in kb_blocks:
            retrieved_texts.extend([doc['content']['text'] for doc in block.get('retrievedDocuments', [])])

        # Compute semantic similarity
        query_emb = model.encode(expected_query)
        doc_embs = model.encode(retrieved_texts)
        similarities = util.cos_sim(query_emb, doc_embs)[0]

        max_similarity = float(similarities.max())
        return {'coverage': max_similarity, 'missing': max_similarity < 0.7}
    except:
        return {'coverage': 0.0, 'missing': True}

