import boto3
import json

class BedrockAgentSession:
    def __init__(self):
        self.bedrock = boto3.client('bedrock-agent-runtime')
        self.sessions = {}

    def invoke_with_session(self, agent_id, agent_alias_id, session_id, input_text):
        # Load or initialize session state
        if session_id not in self.sessions:
            self.sessions[session_id] = {'history': [], 'context': {}}

        session_state = self.sessions[session_id]

        response = self.bedrock.invoke_agent(
            agentId=agent_id,
            agentAliasId=agent_alias_id,
            sessionId=session_id,
            inputText=input_text,
            sessionState={
                'sessionAttributes': session_state['context'],
                'promptSessionAttributes': {'history': json.dumps(session_state['history'][-10:])}
            }
        )

        # Update session state
        session_state['history'].append({'input': input_text, 'response': response})

        return response
